import { useState, useEffect, useRef, useCallback } from 'react';
import { ArrowLeft, Dumbbell, Trophy, TrendingUp, Award } from 'lucide-react';
import { getSessionsForExercise } from '../db';
import { getExercisePRs, buildChartData } from '../utils/stats';
import { fmtShortDate } from '../utils/format';
import { cap } from '../utils/exercises';

// ─── palette (matches gym app design tokens) ──────────────────────────────────
const BG         = '#121212';
const SURFACE    = '#1E1E1E';
const SURFACE2   = '#2D2D2D';
const BORDER     = '#2D2D2D';
const ACCENT     = '#2563EB';
const ACCENT_DIM = 'rgba(37,99,235,0.15)';
const TEXT1      = '#F9FAFB';
const TEXT2      = '#9CA3AF';
const TEXT3      = '#6B7280';
const PILL_BG    = 'rgba(255,255,255,0.06)';
const PR_COLOR   = '#fbbf24';

// ─── SET_REPS_ROWS: reps we show in the Set Records table ─────────────────────
const SET_REPS_ROWS = [1, 2, 3, 4, 5, 6, 8, 10, 12, 15, 20];

// ─── TIME_RANGE helpers ───────────────────────────────────────────────────────
const RANGES = [
  { label: '1M',  months: 1  },
  { label: '3M',  months: 3  },
  { label: '6M',  months: 6  },
  { label: '1Y',  months: 12 },
  { label: 'All', months: null },
];

function filterByRange(points, months) {
  if (!months) return points;
  const cutoff = new Date();
  cutoff.setMonth(cutoff.getMonth() - months);
  return points.filter(p => new Date(p.date) >= cutoff);
}

// ─── SVG Line Chart ───────────────────────────────────────────────────────────
const CHART_W   = 300;
const CHART_H   = 130;
const MARGIN    = { left: 36, right: 8, top: 8, bottom: 22 };
const INNER_W   = CHART_W - MARGIN.left - MARGIN.right;
const INNER_H   = CHART_H - MARGIN.top - MARGIN.bottom;
const GRAD_ID   = 'chartAreaGrad';

function buildBezier(pts) {
  if (pts.length < 2) return '';
  const d = [`M ${pts[0].x} ${pts[0].y}`];
  for (let i = 0; i < pts.length - 1; i++) {
    const p0 = pts[i];
    const p1 = pts[i + 1];
    const cx = (p0.x + p1.x) / 2;
    d.push(`C ${cx} ${p0.y}, ${cx} ${p1.y}, ${p1.x} ${p1.y}`);
  }
  return d.join(' ');
}

function LineChart({ points }) {
  const containerRef = useRef(null);
  const [scaleX, setScaleX] = useState(1);

  useEffect(() => {
    if (!containerRef.current) return;
    const ro = new ResizeObserver(entries => {
      const w = entries[0]?.contentRect.width;
      if (w) setScaleX(w / CHART_W);
    });
    ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  if (!points || points.length === 0) {
    return (
      <div
        style={{
          height: CHART_H,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: TEXT3,
          fontSize: 13,
        }}
      >
        No data for this period
      </div>
    );
  }

  // Compute value range with padding
  const vals   = points.map(p => p.value);
  const rawMin = Math.min(...vals);
  const rawMax = Math.max(...vals);
  const pad    = (rawMax - rawMin) * 0.15 || rawMax * 0.15 || 1;
  const yMin   = rawMin - pad;
  const yMax   = rawMax + pad;
  const yRange = yMax - yMin;

  // Map to SVG coords
  const xScale = points.length > 1 ? INNER_W / (points.length - 1) : INNER_W;
  const toX = i  => MARGIN.left + (points.length > 1 ? i * xScale : INNER_W / 2);
  const toY = v  => MARGIN.top  + INNER_H - ((v - yMin) / yRange) * INNER_H;

  const svgPts = points.map((p, i) => ({ x: toX(i), y: toY(p.value), ...p }));

  const linePath = buildBezier(svgPts);
  const areaPath =
    linePath +
    ` L ${svgPts[svgPts.length - 1].x} ${MARGIN.top + INNER_H}` +
    ` L ${svgPts[0].x} ${MARGIN.top + INNER_H} Z`;

  // Y-axis ticks (3 ticks)
  const yTicks = [0, 0.5, 1].map(t => ({
    value: yMin + t * yRange,
    y: toY(yMin + t * yRange),
  }));

  // X-axis labels — sample up to 5 evenly
  const xLabelCount = Math.min(5, points.length);
  const xLabelIdxs = Array.from({ length: xLabelCount }, (_, i) =>
    Math.round((i / (xLabelCount - 1 || 1)) * (points.length - 1))
  );
  const uniqueXIdxs = [...new Set(xLabelIdxs)];

  const fmtXLabel = iso => {
    const d = new Date(iso);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  const fmtYLabel = v => {
    if (v >= 1000) return `${(v / 1000).toFixed(1)}k`;
    return Math.round(v).toString();
  };

  return (
    <div ref={containerRef} style={{ width: '100%' }}>
      <svg
        viewBox={`0 0 ${CHART_W} ${CHART_H}`}
        style={{ width: '100%', height: CHART_H * scaleX, display: 'block', overflow: 'visible' }}
        preserveAspectRatio="none"
      >
        <defs>
          <linearGradient id={GRAD_ID} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor={ACCENT} stopOpacity="0.35" />
            <stop offset="100%" stopColor={ACCENT} stopOpacity="0.02" />
          </linearGradient>
        </defs>

        {/* Y grid lines + labels */}
        {yTicks.map((t, i) => (
          <g key={i}>
            <line
              x1={MARGIN.left}
              y1={t.y}
              x2={CHART_W - MARGIN.right}
              y2={t.y}
              stroke={BORDER}
              strokeWidth="0.5"
            />
            <text
              x={MARGIN.left - 4}
              y={t.y + 4}
              fontSize="7"
              fill={TEXT3}
              textAnchor="end"
            >
              {fmtYLabel(t.value)}
            </text>
          </g>
        ))}

        {/* Area fill */}
        {points.length > 1 && (
          <path d={areaPath} fill={`url(#${GRAD_ID})`} />
        )}

        {/* Line */}
        {points.length > 1 && (
          <path
            d={linePath}
            fill="none"
            stroke={ACCENT}
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        )}

        {/* X-axis date labels */}
        {uniqueXIdxs.map(idx => (
          <text
            key={idx}
            x={toX(idx)}
            y={CHART_H - 4}
            fontSize="6.5"
            fill={TEXT3}
            textAnchor="middle"
          >
            {fmtXLabel(points[idx].date)}
          </text>
        ))}

        {/* Dots */}
        {svgPts.map((p, i) => (
          <g key={i}>
            {p.isPR ? (
              <>
                <circle cx={p.x} cy={p.y} r={5} fill={PR_COLOR} opacity={0.25} />
                <circle cx={p.x} cy={p.y} r={3} fill={PR_COLOR} />
                <text
                  x={p.x}
                  y={p.y - 7}
                  fontSize="5.5"
                  fill={PR_COLOR}
                  textAnchor="middle"
                  fontWeight="bold"
                >
                  PR
                </text>
              </>
            ) : (
              <circle cx={p.x} cy={p.y} r={2.5} fill={ACCENT} />
            )}
          </g>
        ))}
      </svg>
    </div>
  );
}

// ─── StatCard ─────────────────────────────────────────────────────────────────
function StatCard({ label, value, highlight }) {
  return (
    <div
      style={{
        background: SURFACE,
        border: `1px solid ${highlight ? 'rgba(251,191,36,0.35)' : BORDER}`,
        borderRadius: 10,
        padding: '12px 14px',
        display: 'flex',
        flexDirection: 'column',
        gap: 4,
      }}
    >
      <span style={{ fontSize: 11, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
        {label}
      </span>
      <span style={{ fontSize: 22, fontWeight: 800, color: highlight ? PR_COLOR : TEXT1 }}>
        {value}
      </span>
    </div>
  );
}

// ─── SummaryTab ───────────────────────────────────────────────────────────────
function SummaryTab({ exercise, sessions }) {
  const prs = getExercisePRs(sessions, exercise.name);

  const instructions = exercise.instructions;
  const isTimeBased  = exercise.trackingType === 'time';

  const fmt1RM = v => v > 0 ? `${Math.round(v)} kg` : '—';
  const fmtKg  = v => v > 0 ? `${v} kg` : '—';
  const fmtVol = v => {
    if (v <= 0) return '—';
    if (v >= 1000) return `${(v / 1000).toFixed(1)}k kg`;
    return `${Math.round(v)} kg`;
  };
  const fmtReps = v => v > 0 ? `${v} reps` : '—';

  const setRecordRows = SET_REPS_ROWS.filter(r => prs.setRecords[r]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
      {/* Image / placeholder */}
      <div
        style={{
          width: '100%',
          aspectRatio: '4/3',
          borderRadius: 12,
          overflow: 'hidden',
          background: SURFACE,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        {exercise.imageUrl ? (
          <img
            src={exercise.imageUrl}
            alt={exercise.name}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        ) : (
          <Dumbbell size={64} color={TEXT3} />
        )}
      </div>

      {/* Muscle badges */}
      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
        {exercise.bodyPart && (
          <span
            style={{
              background: ACCENT_DIM,
              border: `1px solid ${ACCENT}`,
              color: ACCENT,
              fontSize: 12,
              padding: '3px 10px',
              borderRadius: 20,
              fontWeight: 600,
            }}
          >
            {cap(exercise.bodyPart)}
          </span>
        )}
        {exercise.equipment && (
          <span
            style={{
              background: PILL_BG,
              border: `1px solid ${BORDER}`,
              color: TEXT2,
              fontSize: 12,
              padding: '3px 10px',
              borderRadius: 20,
            }}
          >
            {cap(exercise.equipment)}
          </span>
        )}
        {exercise.custom && (
          <span
            style={{
              background: 'rgba(251,191,36,0.1)',
              border: '1px solid rgba(251,191,36,0.3)',
              color: PR_COLOR,
              fontSize: 11,
              padding: '3px 10px',
              borderRadius: 20,
              fontWeight: 600,
            }}
          >
            Custom
          </span>
        )}
      </div>

      {/* Instructions */}
      {instructions && (
        <div>
          <div style={{ fontSize: 13, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 8 }}>
            Instructions
          </div>
          {Array.isArray(instructions) ? (
            <ol style={{ paddingLeft: 18, display: 'flex', flexDirection: 'column', gap: 6 }}>
              {instructions.map((step, i) => (
                <li key={i} style={{ fontSize: 14, color: TEXT2, lineHeight: 1.6 }}>
                  {step}
                </li>
              ))}
            </ol>
          ) : (
            instructions.split('\n').filter(Boolean).map((para, i) => (
              <p key={i} style={{ fontSize: 14, color: TEXT2, lineHeight: 1.6, marginBottom: 4 }}>
                {para}
              </p>
            ))
          )}
        </div>
      )}

      {/* Records */}
      {sessions.length > 0 && (
        <>
          <div>
            <div style={{ fontSize: 13, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 10 }}>
              Personal Records
            </div>
            {isTimeBased ? (
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                <StatCard label="Best Duration" value={prs.bestWeight > 0 ? `${prs.bestWeight}s` : '—'} highlight={prs.bestWeight > 0} />
                <StatCard label="Max Reps" value={fmtReps(prs.maxReps)} />
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                <StatCard label="Best Weight" value={fmtKg(prs.bestWeight)} highlight={prs.bestWeight > 0} />
                <StatCard label="Est. 1RM"    value={fmt1RM(prs.best1RM)}   highlight={prs.best1RM > 0}   />
                <StatCard label="Best Volume" value={fmtVol(prs.bestVolume)} />
                <StatCard label="Max Reps"    value={fmtReps(prs.maxReps)} />
              </div>
            )}
          </div>

          {setRecordRows.length > 0 && (
            <div>
              <div style={{ fontSize: 13, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 10 }}>
                Set Records
              </div>
              <div
                style={{
                  background: SURFACE,
                  border: `1px solid ${BORDER}`,
                  borderRadius: 10,
                  overflow: 'hidden',
                }}
              >
                {/* header */}
                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr 1fr',
                    padding: '8px 14px',
                    borderBottom: `1px solid ${BORDER}`,
                  }}
                >
                  {['Reps', 'Weight', 'Date'].map(h => (
                    <span key={h} style={{ fontSize: 11, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                      {h}
                    </span>
                  ))}
                </div>
                {setRecordRows.map(reps => {
                  const rec = prs.setRecords[reps];
                  return (
                    <div
                      key={reps}
                      style={{
                        display: 'grid',
                        gridTemplateColumns: '1fr 1fr 1fr',
                        padding: '9px 14px',
                        borderBottom: `1px solid ${BORDER}`,
                      }}
                    >
                      <span style={{ fontSize: 14, color: TEXT2 }}>{reps}</span>
                      <span style={{ fontSize: 14, fontWeight: 700, color: PR_COLOR }}>{rec.weight} kg</span>
                      <span style={{ fontSize: 12, color: TEXT3 }}>
                        {rec.date ? fmtShortDate(rec.date) : '—'}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </>
      )}

      {sessions.length === 0 && (
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 10,
            padding: '32px 0',
            color: TEXT3,
          }}
        >
          <Trophy size={36} color={TEXT3} />
          <div style={{ fontSize: 14, color: TEXT2, fontWeight: 600 }}>No records yet</div>
          <div style={{ fontSize: 13, textAlign: 'center', maxWidth: 220 }}>
            Complete workouts with this exercise to see your records here.
          </div>
        </div>
      )}
    </div>
  );
}

// ─── HistoryTab ───────────────────────────────────────────────────────────────
function HistoryTab({ exercise, sessions }) {
  if (sessions.length === 0) {
    return (
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: 10,
          padding: '48px 0',
          color: TEXT3,
        }}
      >
        <Dumbbell size={36} color={TEXT3} />
        <div style={{ fontSize: 14, color: TEXT2, fontWeight: 600 }}>No history yet</div>
        <div style={{ fontSize: 13, textAlign: 'center', maxWidth: 220 }}>
          Log this exercise in a workout to see your history here.
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 0 }}>
      {sessions.map(session => {
        const ex = session.exercises?.find(e => e.name === exercise.name);
        if (!ex) return null;
        const completedSets = ex.sets?.filter(s => s.completed) || [];
        const isTimeBased   = exercise.trackingType === 'time' || ex.trackingType === 'time';

        return (
          <div
            key={session.id}
            style={{
              borderBottom: `1px solid ${BORDER}`,
              padding: '14px 0',
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 8 }}>
              <span style={{ fontSize: 15, fontWeight: 700, color: TEXT1 }}>
                {session.title || 'Workout'}
              </span>
              <span style={{ fontSize: 12, color: TEXT3 }}>
                {session.date ? fmtShortDate(session.date) : ''}
              </span>
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
              {completedSets.length === 0 && (
                <span style={{ fontSize: 13, color: TEXT3 }}>No completed sets</span>
              )}
              {completedSets.map((set, i) => {
                let label;
                if (isTimeBased) {
                  label = set.time ? `${set.time}s` : '—';
                } else {
                  const reps   = set.reps   ? `${set.reps} reps`   : '';
                  const weight = set.weight ? `${set.weight} kg`   : '';
                  label = [weight, reps].filter(Boolean).join(' × ');
                }
                return (
                  <span
                    key={i}
                    style={{
                      fontSize: 13,
                      color: TEXT2,
                      background: SURFACE,
                      border: `1px solid ${BORDER}`,
                      borderRadius: 6,
                      padding: '3px 9px',
                    }}
                  >
                    {label || '—'}
                  </span>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── ChartsTab ────────────────────────────────────────────────────────────────
function ChartsTab({ exercise, sessions }) {
  const isTimeBased = exercise.trackingType === 'time';

  const METRICS = isTimeBased
    ? [
        { key: 'duration', label: 'Best Duration', unit: 's' },
        { key: 'volume',   label: 'Total Duration', unit: 's' },
        { key: 'reps',     label: 'Sets Done',       unit: '' },
      ]
    : [
        { key: 'weight', label: 'Best Weight', unit: 'kg' },
        { key: '1rm',    label: 'Est. 1RM',    unit: 'kg' },
        { key: 'volume', label: 'Volume',      unit: 'kg' },
        { key: 'reps',   label: 'Max Reps',    unit: '' },
      ];

  const [metric,    setMetric]    = useState(METRICS[0].key);
  const [rangeIdx,  setRangeIdx]  = useState(RANGES.length - 1); // default: All

  const allPoints  = buildChartData(sessions, exercise.name, metric);
  const filtered   = filterByRange(allPoints, RANGES[rangeIdx].months);

  const currentMetaDef = METRICS.find(m => m.key === metric) || METRICS[0];

  // Current value = last filtered point
  const currentPoint   = filtered.length > 0 ? filtered[filtered.length - 1] : null;
  const allTimeMax     = allPoints.length > 0 ? Math.max(...allPoints.map(p => p.value)) : 0;
  const isCurrentPR    = currentPoint && allPoints.length > 1 && currentPoint.value >= allTimeMax;

  const fmtValue = v => {
    if (v === null || v === undefined) return '—';
    if (currentMetaDef.key === 'volume' && v >= 1000) return `${(v / 1000).toFixed(1)}k`;
    if (Number.isInteger(v)) return v.toString();
    return v.toFixed(1);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      {/* Metric pills */}
      <div
        style={{
          display: 'flex',
          gap: 6,
          overflowX: 'auto',
          scrollbarWidth: 'none',
          paddingBottom: 2,
        }}
      >
        {METRICS.map(m => {
          const active = metric === m.key;
          return (
            <button
              key={m.key}
              onClick={() => setMetric(m.key)}
              style={{
                flexShrink: 0,
                padding: '6px 14px',
                borderRadius: 20,
                fontSize: 13,
                fontWeight: active ? 600 : 400,
                border: active ? `1.5px solid ${ACCENT}` : `1px solid ${BORDER}`,
                background: active ? ACCENT_DIM : 'transparent',
                color: active ? ACCENT : TEXT2,
                cursor: 'pointer',
                whiteSpace: 'nowrap',
                transition: 'all 0.15s',
              }}
            >
              {m.label}
            </button>
          );
        })}
      </div>

      {/* Time range segmented control */}
      <div
        style={{
          display: 'flex',
          background: SURFACE,
          border: `1px solid ${BORDER}`,
          borderRadius: 8,
          padding: 3,
          gap: 2,
        }}
      >
        {RANGES.map((r, i) => {
          const active = rangeIdx === i;
          return (
            <button
              key={r.label}
              onClick={() => setRangeIdx(i)}
              style={{
                flex: 1,
                padding: '6px 0',
                borderRadius: 6,
                fontSize: 12,
                fontWeight: active ? 700 : 400,
                border: 'none',
                background: active ? ACCENT : 'transparent',
                color: active ? '#fff' : TEXT3,
                cursor: 'pointer',
                transition: 'all 0.15s',
              }}
            >
              {r.label}
            </button>
          );
        })}
      </div>

      {/* Current value headline */}
      {currentPoint && (
        <div
          style={{
            background: SURFACE,
            border: `1px solid ${BORDER}`,
            borderRadius: 10,
            padding: '14px 16px',
            display: 'flex',
            alignItems: 'center',
            gap: 10,
          }}
        >
          <TrendingUp size={18} color={ACCENT} />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 11, color: TEXT3, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 2 }}>
              Latest — {fmtShortDate(currentPoint.date)}
            </div>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: 6 }}>
              <span style={{ fontSize: 28, fontWeight: 800, color: TEXT1 }}>
                {fmtValue(currentPoint.value)}
              </span>
              {currentMetaDef.unit && (
                <span style={{ fontSize: 14, color: TEXT3 }}>{currentMetaDef.unit}</span>
              )}
              {isCurrentPR && (
                <span
                  style={{
                    fontSize: 11,
                    fontWeight: 700,
                    background: 'rgba(251,191,36,0.15)',
                    border: '1px solid rgba(251,191,36,0.4)',
                    color: PR_COLOR,
                    padding: '2px 8px',
                    borderRadius: 10,
                  }}
                >
                  PR
                </span>
              )}
            </div>
          </div>
          <Award size={18} color={isCurrentPR ? PR_COLOR : TEXT3} />
        </div>
      )}

      {/* Chart */}
      <div
        style={{
          background: SURFACE,
          border: `1px solid ${BORDER}`,
          borderRadius: 12,
          padding: '14px 10px 8px',
        }}
      >
        <LineChart points={filtered} />
      </div>

      {filtered.length > 0 && (
        <div style={{ fontSize: 12, color: TEXT3, textAlign: 'center' }}>
          {filtered.length} session{filtered.length !== 1 ? 's' : ''} in this period
        </div>
      )}
    </div>
  );
}

// ─── ExerciseDetail ───────────────────────────────────────────────────────────
export default function ExerciseDetail({ exercise, onBack }) {
  const [tab, setTab]       = useState('summary');
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    setLoading(true);
    getSessionsForExercise(exercise.name)
      .then(s => setSessions(s || []))
      .catch(() => setSessions([]))
      .finally(() => setLoading(false));
  }, [exercise.name]);

  const TABS = [
    { id: 'summary', label: 'Summary' },
    { id: 'history', label: 'History' },
    { id: 'charts',  label: 'Charts'  },
  ];

  return (
    <div
      className="ex-detail"
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 300,
        background: BG,
        overflowY: 'auto',
        display: 'flex',
        flexDirection: 'column',
        animation: 'slideInRight 0.22s cubic-bezier(0.25,0.46,0.45,0.94)',
      }}
    >
      <style>{`
        @keyframes slideInRight {
          from { transform: translateX(100%); opacity: 0.5; }
          to   { transform: translateX(0);    opacity: 1;   }
        }
      `}</style>

      {/* ── Header ─────────────────────────────────────────────────────────── */}
      <div
        style={{
          position: 'sticky',
          top: 0,
          zIndex: 10,
          background: BG,
          borderBottom: `1px solid ${BORDER}`,
          padding: '12px 16px',
          flexShrink: 0,
        }}
      >
        {/* top row */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
          <button
            onClick={onBack}
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              padding: 4,
              color: TEXT2,
              display: 'flex',
              alignItems: 'center',
              flexShrink: 0,
            }}
          >
            <ArrowLeft size={22} />
          </button>
          <h1
            style={{
              fontSize: 20,
              fontWeight: 800,
              color: TEXT1,
              flex: 1,
              minWidth: 0,
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
            }}
          >
            {exercise.name}
          </h1>
        </div>

        {/* badges */}
        <div style={{ display: 'flex', gap: 6, paddingLeft: 36, flexWrap: 'wrap' }}>
          {exercise.equipment && (
            <span
              style={{
                fontSize: 11,
                color: TEXT3,
                background: PILL_BG,
                padding: '2px 8px',
                borderRadius: 10,
              }}
            >
              {cap(exercise.equipment)}
            </span>
          )}
          {exercise.bodyPart && (
            <span
              style={{
                fontSize: 11,
                color: ACCENT,
                background: ACCENT_DIM,
                padding: '2px 8px',
                borderRadius: 10,
                fontWeight: 600,
              }}
            >
              {cap(exercise.bodyPart)}
            </span>
          )}
        </div>

        {/* Tab bar */}
        <div
          style={{
            display: 'flex',
            gap: 0,
            marginTop: 14,
            borderBottom: `1px solid ${BORDER}`,
          }}
        >
          {TABS.map(t => {
            const active = tab === t.id;
            return (
              <button
                key={t.id}
                onClick={() => setTab(t.id)}
                style={{
                  flex: 1,
                  padding: '8px 0',
                  background: 'none',
                  border: 'none',
                  borderBottom: active ? `2px solid ${ACCENT}` : '2px solid transparent',
                  color: active ? ACCENT : TEXT3,
                  fontSize: 14,
                  fontWeight: active ? 700 : 400,
                  cursor: 'pointer',
                  transition: 'color 0.15s',
                  marginBottom: -1,
                }}
              >
                {t.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* ── Tab content ────────────────────────────────────────────────────── */}
      <div style={{ flex: 1, padding: '16px 16px 32px', minWidth: 0 }}>
        {loading ? (
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: 48,
              color: TEXT3,
              fontSize: 14,
            }}
          >
            Loading…
          </div>
        ) : (
          <>
            {tab === 'summary' && (
              <SummaryTab exercise={exercise} sessions={sessions} />
            )}
            {tab === 'history' && (
              <HistoryTab exercise={exercise} sessions={sessions} />
            )}
            {tab === 'charts' && (
              <ChartsTab exercise={exercise} sessions={sessions} />
            )}
          </>
        )}
      </div>
    </div>
  );
}
