import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import {
  ChevronLeft, ChevronRight, ChevronDown, ChevronUp,
  MoreHorizontal, ArrowLeft, TrendingUp, Dumbbell, Calendar as CalendarIcon,
} from 'lucide-react';
import { getAllSessions, deleteSession, saveRoutine } from '../db';
import { fmtDuration, fmtDate, fmtTimeOfDay, fmtShortDate } from '../utils/format';
import { calcVolume, calcSets } from '../utils/stats';
import ProgressTab from './ProgressTab';
import ExercisesTab from './ExercisesTab';

// ── Volume formatting ──────────────────────────────────────────────────────────
function fmtVolLocal(kg) {
  if (!kg || kg === 0) return '—';
  if (kg >= 1000) return `${(kg / 1000).toFixed(1)}k kg`;
  return `${Math.round(kg)} kg`;
}

// ── SessionCard ────────────────────────────────────────────────────────────────
function SessionCard({ session, onDelete, onCopy }) {
  const [expanded, setExpanded] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const longPressTimer = useRef(null);
  const menuRef = useRef(null);

  const volume = calcVolume(session.exercises || []);
  const sets   = calcSets(session.exercises || []);

  // Close menu on outside click
  useEffect(() => {
    if (!menuOpen) return;
    const handler = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) {
        setMenuOpen(false);
        setConfirmDelete(false);
      }
    };
    document.addEventListener('mousedown', handler);
    document.addEventListener('touchstart', handler);
    return () => {
      document.removeEventListener('mousedown', handler);
      document.removeEventListener('touchstart', handler);
    };
  }, [menuOpen]);

  const handleLongPressStart = () => {
    longPressTimer.current = setTimeout(() => setMenuOpen(true), 500);
  };
  const handleLongPressEnd = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
  };

  return (
    <div
      style={{
        background: 'var(--bg2)',
        borderRadius: 14,
        border: '1px solid var(--border)',
        marginBottom: 10,
        overflow: 'hidden',
        position: 'relative',
      }}
      onMouseDown={handleLongPressStart}
      onMouseUp={handleLongPressEnd}
      onMouseLeave={handleLongPressEnd}
      onTouchStart={handleLongPressStart}
      onTouchEnd={handleLongPressEnd}
    >
      {/* Card header */}
      <div
        style={{ padding: '14px 14px 10px', cursor: 'pointer' }}
        onClick={() => setExpanded(e => !e)}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontWeight: 700, fontSize: 15, color: 'var(--text)', marginBottom: 2 }}>
              {session.title || 'Workout'}
            </div>
            <div style={{ fontSize: 12, color: 'var(--text3)' }}>
              {fmtTimeOfDay(session.date)}
            </div>
          </div>

          {/* Context menu trigger */}
          <button
            onClick={(e) => { e.stopPropagation(); setMenuOpen(o => !o); setConfirmDelete(false); }}
            style={{ background: 'none', border: 'none', color: 'var(--text3)', cursor: 'pointer', padding: '0 0 0 8px', display: 'flex', alignItems: 'center' }}
          >
            <MoreHorizontal size={18} />
          </button>
        </div>

        {/* Stats row */}
        <div style={{ display: 'flex', gap: 18, marginTop: 10 }}>
          {[
            { label: 'Duration', value: fmtDuration(session.duration) },
            { label: 'Volume',   value: fmtVolLocal(volume) },
            { label: 'Sets',     value: String(sets) },
          ].map(({ label, value }) => (
            <div key={label}>
              <div style={{ fontSize: 11, color: 'var(--text3)', fontWeight: 600, marginBottom: 2 }}>{label}</div>
              <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--text)' }}>{value}</div>
            </div>
          ))}
        </div>

        {/* Expand chevron */}
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: 6 }}>
          {expanded ? <ChevronUp size={16} color="var(--text3)" /> : <ChevronDown size={16} color="var(--text3)" />}
        </div>
      </div>

      {/* Expanded exercise list */}
      {expanded && (
        <div style={{ padding: '0 14px 14px', borderTop: '1px solid var(--border)' }}>
          {(session.exercises || []).map((ex, i) => {
            const done = (ex.sets || []).filter(s => s.completed);
            if (!done.length) return null;
            return (
              <div key={i} style={{ marginTop: 10 }}>
                <div style={{ fontWeight: 600, fontSize: 13, color: 'var(--text)', marginBottom: 4 }}>{ex.name}</div>
                {done.map((set, j) => (
                  <div key={j} style={{ fontSize: 13, color: 'var(--text2)', paddingLeft: 8, marginBottom: 2, display: 'flex', gap: 10 }}>
                    <span style={{ color: 'var(--text3)', minWidth: 18 }}>{j + 1}</span>
                    {set.time > 0 && !set.reps
                      ? <span>{set.time}s</span>
                      : <span>{set.reps} reps{+set.weight > 0 ? ` @ ${set.weight}kg` : ''}</span>
                    }
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      )}

      {/* Context menu */}
      {menuOpen && (
        <div
          ref={menuRef}
          style={{
            position: 'absolute', top: 36, right: 10, zIndex: 50,
            background: 'var(--bg3)', border: '1px solid var(--border)',
            borderRadius: 10, overflow: 'hidden', minWidth: 160,
            boxShadow: '0 6px 24px rgba(0,0,0,0.45)',
          }}
        >
          <button
            onClick={(e) => { e.stopPropagation(); onCopy(session); setMenuOpen(false); }}
            style={menuItemStyle}
          >
            Copy Workout
          </button>
          {!confirmDelete ? (
            <button
              onClick={(e) => { e.stopPropagation(); setConfirmDelete(true); }}
              style={{ ...menuItemStyle, color: '#EF4444' }}
            >
              Delete
            </button>
          ) : (
            <button
              onClick={(e) => { e.stopPropagation(); onDelete(session.id); setMenuOpen(false); }}
              style={{ ...menuItemStyle, color: '#EF4444', fontWeight: 700 }}
            >
              Confirm Delete
            </button>
          )}
        </div>
      )}
    </div>
  );
}

const menuItemStyle = {
  display: 'block', width: '100%', textAlign: 'left',
  padding: '12px 16px', background: 'none', border: 'none',
  color: 'var(--text)', fontSize: 14, cursor: 'pointer',
  borderBottom: '1px solid var(--border)',
};

// ── DayDetail overlay ─────────────────────────────────────────────────────────
function DayDetail({ date, sessions, onClose }) {
  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 400,
      background: 'var(--bg)',
      display: 'flex', flexDirection: 'column',
      animation: 'slideUp 0.22s ease-out',
    }}>
      <style>{`
        @keyframes slideUp {
          from { transform: translateY(32px); opacity: 0; }
          to   { transform: translateY(0);    opacity: 1; }
        }
      `}</style>

      {/* Header */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 12,
        padding: '16px 16px 12px',
        borderBottom: '1px solid var(--border)',
        flexShrink: 0,
      }}>
        <button
          onClick={onClose}
          style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 6, fontSize: 15 }}
        >
          <ArrowLeft size={20} />
        </button>
        <span style={{ fontWeight: 700, fontSize: 17 }}>{fmtShortDate(date)}</span>
      </div>

      {/* Sessions list */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>
        {sessions.map((session) => {
          const sets = calcSets(session.exercises || []);
          return (
            <div key={session.id} style={{
              background: 'var(--bg2)',
              borderRadius: 12,
              border: '1px solid var(--border)',
              padding: '14px',
              marginBottom: 12,
            }}>
              <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 2 }}>{session.title || 'Workout'}</div>
              <div style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 10 }}>
                {fmtDuration(session.duration)} · {sets} sets
              </div>
              {(session.exercises || []).map((ex, i) => {
                const done = (ex.sets || []).filter(s => s.completed);
                if (!done.length) return null;
                return (
                  <div key={i} style={{ marginBottom: 8 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 3 }}>{ex.name}</div>
                    {done.map((set, j) => (
                      <div key={j} style={{ fontSize: 13, color: 'var(--text2)', paddingLeft: 8, marginBottom: 2, display: 'flex', gap: 10 }}>
                        <span style={{ color: 'var(--text3)', minWidth: 18 }}>{j + 1}</span>
                        {set.time > 0 && !set.reps
                          ? <span>{set.time}s</span>
                          : <span>{set.reps} reps{+set.weight > 0 ? ` @ ${set.weight}kg` : ''}</span>
                        }
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Calendar ───────────────────────────────────────────────────────────────────
const DAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];

function Calendar({ sessions, onDayClick }) {
  const [month, setMonth] = useState(() => {
    const d = new Date();
    d.setDate(1);
    d.setHours(0, 0, 0, 0);
    return d;
  });

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const sessionDates = new Map();
  for (const s of sessions) {
    const key = new Date(s.date).toLocaleDateString('en-CA');
    if (!sessionDates.has(key)) sessionDates.set(key, []);
    sessionDates.get(key).push(s);
  }

  const year = month.getFullYear();
  const monthIdx = month.getMonth();
  const firstDow = new Date(year, monthIdx, 1).getDay();
  const daysInMonth = new Date(year, monthIdx + 1, 0).getDate();

  const cells = [];
  for (let i = 0; i < firstDow; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  const prevMonth = () => setMonth(m => { const n = new Date(m); n.setMonth(n.getMonth() - 1); return n; });
  const nextMonth = () => setMonth(m => { const n = new Date(m); n.setMonth(n.getMonth() + 1); return n; });

  return (
    <div style={{ padding: '16px 0 0' }}>
      {/* Month nav */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 14, padding: '0 4px' }}>
        <button
          onClick={prevMonth}
          style={{ background: 'none', border: 'none', color: 'var(--text2)', cursor: 'pointer', padding: '4px 8px', borderRadius: 8, display: 'flex', alignItems: 'center' }}
        >
          <ChevronLeft size={20} />
        </button>
        <span style={{ fontWeight: 600, fontSize: 15, color: 'var(--text)' }}>
          {MONTH_NAMES[monthIdx]} {year}
        </span>
        <button
          onClick={nextMonth}
          style={{ background: 'none', border: 'none', color: 'var(--text2)', cursor: 'pointer', padding: '4px 8px', borderRadius: 8, display: 'flex', alignItems: 'center' }}
        >
          <ChevronRight size={20} />
        </button>
      </div>

      {/* Day headers */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', marginBottom: 6 }}>
        {DAY_LABELS.map(d => (
          <div key={d} style={{ textAlign: 'center', fontSize: 11, color: 'var(--text3)', fontWeight: 600, padding: '2px 0' }}>
            {d}
          </div>
        ))}
      </div>

      {/* Day cells */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 3 }}>
        {cells.map((day, idx) => {
          if (!day) return <div key={`empty-${idx}`} />;

          const cellDate = new Date(year, monthIdx, day);
          cellDate.setHours(0, 0, 0, 0);
          const dateKey = cellDate.toLocaleDateString('en-CA');
          const hasSessions = sessionDates.has(dateKey);
          const isToday = cellDate.getTime() === today.getTime();

          return (
            <div
              key={day}
              onClick={() => hasSessions && onDayClick(cellDate.toISOString(), sessionDates.get(dateKey))}
              style={{
                textAlign: 'center',
                padding: '6px 0',
                borderRadius: 8,
                fontSize: 13,
                fontWeight: hasSessions ? 700 : 400,
                cursor: hasSessions ? 'pointer' : 'default',
                background: hasSessions ? 'var(--accent)' : 'transparent',
                color: hasSessions ? '#fff' : isToday ? 'var(--text3)' : 'var(--text2)',
                outline: isToday ? '2px solid var(--text3)' : 'none',
                outlineOffset: '-2px',
                transition: 'background 0.15s',
              }}
            >
              {day}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Toast ──────────────────────────────────────────────────────────────────────
function Toast({ message, onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 2400);
    return () => clearTimeout(t);
  }, [onDone]);

  return (
    <div style={{
      position: 'fixed', bottom: 80, left: '50%', transform: 'translateX(-50%)',
      background: 'var(--bg3)', color: 'var(--text)',
      padding: '10px 20px', borderRadius: 10,
      fontSize: 14, fontWeight: 500,
      boxShadow: '0 4px 20px rgba(0,0,0,0.5)',
      zIndex: 500,
      border: '1px solid var(--border)',
      whiteSpace: 'nowrap',
    }}>
      {message}
    </div>
  );
}

// ── ActivityChart ──────────────────────────────────────────────────────────────
function ActivityChart({ sessions }) {
  const BAR_COUNT = 8;
  const BAR_MAX_H = 36;

  const weeks = useMemo(() => {
    const now = new Date();
    // Start of current week (Monday)
    const dow = now.getDay(); // 0=Sun
    const mondayOffset = dow === 0 ? -6 : 1 - dow;
    const thisMonday = new Date(now);
    thisMonday.setDate(now.getDate() + mondayOffset);
    thisMonday.setHours(0, 0, 0, 0);

    const buckets = [];
    for (let i = BAR_COUNT - 1; i >= 0; i--) {
      const start = new Date(thisMonday);
      start.setDate(thisMonday.getDate() - i * 7);
      const end = new Date(start);
      end.setDate(start.getDate() + 7);
      buckets.push({ start, end, totalDuration: 0, count: 0 });
    }

    for (const s of sessions) {
      const d = new Date(s.date).getTime();
      for (const b of buckets) {
        if (d >= b.start.getTime() && d < b.end.getTime()) {
          b.totalDuration += s.duration || 0;
          b.count++;
          break;
        }
      }
    }
    return buckets;
  }, [sessions]);

  const maxDuration = Math.max(...weeks.map(w => w.totalDuration), 1);
  const thisWeekSecs = weeks[weeks.length - 1]?.totalDuration ?? 0;
  const thisWeekHrs = (thisWeekSecs / 3600).toFixed(1);

  return (
    <div style={{ padding: '4px 16px 20px' }}>
      <div style={{ fontSize: 13, color: 'var(--text3)', marginBottom: 10 }}>
        <span style={{ fontSize: 22, fontWeight: 800, color: 'var(--text)' }}>{thisWeekHrs}</span>
        {' '}hrs this week
      </div>
      <div style={{ display: 'flex', alignItems: 'flex-end', gap: 5, height: BAR_MAX_H + 4 }}>
        {weeks.map((w, i) => {
          const h = w.totalDuration > 0
            ? Math.max(4, Math.round((w.totalDuration / maxDuration) * BAR_MAX_H))
            : 3;
          const isCurrent = i === weeks.length - 1;
          return (
            <div
              key={i}
              style={{
                flex: 1,
                height: h,
                borderRadius: '3px 3px 0 0',
                background: w.totalDuration > 0
                  ? isCurrent ? 'var(--accent)' : 'var(--bg4, var(--bg3))'
                  : 'var(--border)',
                transition: 'height 0.3s ease',
              }}
            />
          );
        })}
      </div>
    </div>
  );
}

// ── DashboardTile ──────────────────────────────────────────────────────────────
function DashboardTile({ icon: Icon, label, onTap }) {
  return (
    <button
      onClick={onTap}
      style={{
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        gap: 8,
        padding: '18px 8px',
        background: 'var(--bg2)',
        border: '1px solid var(--border)',
        borderRadius: 14,
        cursor: 'pointer',
        color: 'var(--text)',
        transition: 'background 0.15s',
      }}
    >
      <Icon size={24} color="var(--accent)" />
      <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--text2)' }}>{label}</span>
    </button>
  );
}

// ── CalendarView ──────────────────────────────────────────────────────────────
function CalendarView({ sessions, onBack }) {
  const [expandedDay, setExpandedDay] = useState(null);

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column', background: 'var(--bg)' }}>
      {/* Header */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 12,
        padding: '56px 16px 14px',
        borderBottom: '1px solid var(--border)',
        flexShrink: 0,
      }}>
        <button
          onClick={onBack}
          style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '0 4px 0 0' }}
        >
          <ArrowLeft size={22} />
        </button>
        <h1 style={{ fontSize: 28, fontWeight: 800, color: 'var(--text)' }}>Calendar</h1>
      </div>

      <div style={{ flex: 1, overflowY: 'auto', padding: '0 16px 32px' }}>
        <Calendar sessions={sessions} onDayClick={(dateIso, daySessions) => setExpandedDay({ date: dateIso, sessions: daySessions })} />
      </div>

      {expandedDay && (
        <DayDetail
          date={expandedDay.date}
          sessions={expandedDay.sessions}
          onClose={() => setExpandedDay(null)}
        />
      )}
    </div>
  );
}

// ── HistoryTab ─────────────────────────────────────────────────────────────────
export default function HistoryTab({ active }) {
  const [sessions, setSessions] = useState([]);
  const [view, setView] = useState('main'); // 'main' | 'statistics' | 'exercises' | 'calendar'
  const [expandedDay, setExpandedDay] = useState(null);
  const [toast, setToast] = useState(null);

  const loadSessions = useCallback(async () => {
    const all = await getAllSessions();
    all.sort((a, b) => new Date(b.date) - new Date(a.date));
    setSessions(all);
  }, []);

  useEffect(() => { if (active) loadSessions(); }, [active, loadSessions]);

  const handleDelete = useCallback(async (id) => {
    await deleteSession(id);
    setSessions(prev => prev.filter(s => s.id !== id));
  }, []);

  const handleCopy = useCallback(async (session) => {
    const routine = {
      id: `routine-copy-${Date.now()}`,
      title: session.title || 'Copied Workout',
      createdAt: new Date().toISOString(),
      exercises: (session.exercises || []).map(ex => ({
        name: ex.name,
        sets: (ex.sets || []).filter(s => s.completed).map(s => ({ ...s, completed: false })),
      })),
    };
    await saveRoutine(routine);
    setToast('Copied to My Routines');
  }, []);

  // Group sessions by date label for Recent Workouts
  const groups = useMemo(() => {
    const result = [];
    const seen = new Map();
    for (const s of sessions) {
      const label = fmtDate(s.date);
      if (!seen.has(label)) {
        seen.set(label, []);
        result.push({ label, items: seen.get(label) });
      }
      seen.get(label).push(s);
    }
    return result;
  }, [sessions]);

  return (
    <>
      {/* ── Main view ── */}
      <div style={{ display: view === 'main' ? 'flex' : 'none', flexDirection: 'column', height: '100vh', background: 'var(--bg)' }}>
        {/* Header */}
        <div style={{
          padding: '56px 16px 16px',
          borderBottom: '1px solid var(--border)',
          flexShrink: 0,
        }}>
          <h1 style={{ fontSize: 28, fontWeight: 800, color: 'var(--text)' }}>History</h1>
        </div>

        {/* Scrollable body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '0 0 80px' }}>

          {/* Activity chart */}
          <div style={{ paddingTop: 20 }}>
            <ActivityChart sessions={sessions} />
          </div>

          {/* Dashboard tiles */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 10, padding: '0 16px', marginBottom: 24 }}>
            <DashboardTile icon={TrendingUp}   label="Statistics" onTap={() => setView('statistics')} />
            <DashboardTile icon={Dumbbell}     label="Exercises"  onTap={() => setView('exercises')} />
            <DashboardTile icon={CalendarIcon} label="Calendar"   onTap={() => setView('calendar')} />
          </div>

          {/* Recent Workouts */}
          <div style={{ padding: '0 16px' }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 14 }}>Recent Workouts</h2>
            {sessions.length === 0 ? (
              <div style={{ color: 'var(--text3)', fontSize: 14, textAlign: 'center', padding: '32px 0' }}>
                No workouts yet. Complete a session to see it here.
              </div>
            ) : (
              groups.map(({ label, items }) => (
                <div key={label}>
                  <div style={{
                    fontSize: 12, fontWeight: 700, color: 'var(--text3)',
                    textTransform: 'uppercase', letterSpacing: '0.8px',
                    marginBottom: 8, marginTop: 16,
                  }}>
                    {label}
                  </div>
                  {items.map(session => (
                    <SessionCard
                      key={session.id}
                      session={session}
                      onDelete={handleDelete}
                      onCopy={handleCopy}
                    />
                  ))}
                </div>
              ))
            )}
          </div>
        </div>

        {/* Day detail overlay */}
        {expandedDay && (
          <DayDetail
            date={expandedDay.date}
            sessions={expandedDay.sessions}
            onClose={() => setExpandedDay(null)}
          />
        )}
      </div>

      {/* ── Sub-view overlays ── */}
      {view === 'statistics' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: 'var(--bg)' }}>
          <ProgressTab active={true} onBack={() => setView('main')} />
        </div>
      )}
      {view === 'exercises' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: '#020210' }}>
          <ExercisesTab onBack={() => setView('main')} />
        </div>
      )}
      {view === 'calendar' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: 'var(--bg)' }}>
          <CalendarView sessions={sessions} onBack={() => setView('main')} />
        </div>
      )}

      {/* Toast */}
      {toast && <Toast message={toast} onDone={() => setToast(null)} />}
    </>
  );
}
