import { useState, useRef, useEffect } from 'react';
import {
  X,
  ChevronDown,
  ChevronUp,
  MoreVertical,
  Check,
  Plus,
  Minus,
  FileText,
  Clock,
  Link,
  ArrowUp,
  ArrowDown,
  Trash2,
} from 'lucide-react';
import { useWorkout } from '../contexts/WorkoutContext';
import { useApp } from '../contexts/AppContext';
import { fmtTime, fmtVolume, fmtDuration } from '../utils/format';
import { calcVolume, calcSets } from '../utils/stats';
import ExercisesTab from './ExercisesTab';

// ── Set type metadata ─────────────────────────────────────────────────────────
const SET_TYPES = {
  N: { label: 'N', bg: '#374151', color: '#9CA3AF' },
  W: { label: 'W', bg: '#78350F', color: '#F59E0B' },
  D: { label: 'D', bg: '#4C1D95', color: '#A78BFA' },
  F: { label: 'F', bg: '#7F1D1D', color: '#F87171' },
};

// ── PR Banner ─────────────────────────────────────────────────────────────────
function PrBanner({ prBanner }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (prBanner) {
      setVisible(true);
    } else {
      setVisible(false);
    }
  }, [prBanner]);

  if (!prBanner) return null;

  return (
    <div
      style={{
        ...styles.prBanner,
        transform: visible ? 'translateY(0)' : 'translateY(-120%)',
        opacity: visible ? 1 : 0,
        transition: 'transform 0.35s cubic-bezier(0.34,1.56,0.64,1), opacity 0.25s',
      }}
    >
      🏆 New PR — {prBanner.exerciseName}: {prBanner.value} kg
    </div>
  );
}

// ── Rest Timer Overlay ────────────────────────────────────────────────────────
function RestTimerOverlay({ restTimer, onSkip, onAdjust }) {
  if (!restTimer) return null;

  const { remaining, total } = restTimer;
  const r = 22;
  const circ = 2 * Math.PI * r;
  const progress = total > 0 ? remaining / total : 0;
  const dashOffset = circ * (1 - progress);

  return (
    <div style={styles.restTimerWrap}>
      <div style={styles.restTimerCard}>
        <button
          style={styles.restAdjBtn}
          onClick={() => onAdjust(-15)}
          aria-label="Subtract 15 seconds"
        >
          <Minus size={14} />
          <span style={{ fontSize: 11, marginLeft: 2 }}>15s</span>
        </button>

        <div style={styles.restCircleWrap}>
          <svg width={64} height={64} viewBox="0 0 64 64">
            <circle
              cx={32}
              cy={32}
              r={r}
              fill="none"
              stroke="#1F2937"
              strokeWidth={4}
            />
            <circle
              cx={32}
              cy={32}
              r={r}
              fill="none"
              stroke="#3B82F6"
              strokeWidth={4}
              strokeDasharray={circ}
              strokeDashoffset={dashOffset}
              strokeLinecap="round"
              transform="rotate(-90 32 32)"
              style={{ transition: 'stroke-dashoffset 0.9s linear' }}
            />
          </svg>
          <span style={styles.restSecs}>{remaining}s</span>
        </div>

        <button
          style={styles.restAdjBtn}
          onClick={() => onAdjust(15)}
          aria-label="Add 15 seconds"
        >
          <Plus size={14} />
          <span style={{ fontSize: 11, marginLeft: 2 }}>15s</span>
        </button>

        <button
          style={styles.restSkipBtn}
          onClick={onSkip}
          aria-label="Skip rest"
        >
          <X size={16} />
        </button>
      </div>
    </div>
  );
}

// ── Set Type Badge ────────────────────────────────────────────────────────────
function SetTypeBadge({ type, onClick }) {
  const meta = SET_TYPES[type] ?? SET_TYPES.N;
  return (
    <button
      style={{
        background: meta.bg,
        color: meta.color,
        border: 'none',
        borderRadius: 6,
        fontWeight: 700,
        fontSize: 12,
        width: 28,
        height: 28,
        cursor: 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0,
      }}
      onClick={onClick}
      aria-label={`Set type: ${type}`}
    >
      {meta.label}
    </button>
  );
}

// ── Set Row ───────────────────────────────────────────────────────────────────
function SetRow({ set, setIdx, exIdx, isTimeBased }) {
  const { updateSet, completeSet, cycleSetType, removeSet, autoFillPrev } = useWorkout();
  const { settings } = useApp();

  const prevLabel =
    set.previous
      ? `${set.previous.weight || '—'}×${set.previous.reps || set.previous.time || '—'}`
      : '—';

  return (
    <div
      style={{
        ...styles.setRow,
        background: set.completed ? 'rgba(34,197,94,0.07)' : 'transparent',
        transition: 'background 0.2s',
      }}
    >
      {/* TYPE */}
      <SetTypeBadge
        type={set.type || 'N'}
        onClick={() => cycleSetType(exIdx, setIdx)}
      />

      {/* SET number */}
      <span style={styles.setNum}>{setIdx + 1}</span>

      {/* PREVIOUS */}
      <button
        style={styles.prevLabel}
        onClick={() => autoFillPrev(exIdx, setIdx)}
        aria-label="Auto-fill from previous"
      >
        {prevLabel}
      </button>

      {/* KG / LBS input */}
      <input
        style={{
          ...styles.setInput,
          borderColor: set.completed ? 'rgba(34,197,94,0.35)' : '#374151',
        }}
        type="number"
        inputMode="decimal"
        placeholder="—"
        value={set.weight ?? ''}
        onChange={e => updateSet(exIdx, setIdx, 'weight', e.target.value)}
      />

      {/* REPS or SEC */}
      <input
        style={{
          ...styles.setInput,
          borderColor: set.completed ? 'rgba(34,197,94,0.35)' : '#374151',
        }}
        type="number"
        inputMode="numeric"
        placeholder="—"
        value={isTimeBased ? (set.time ?? '') : (set.reps ?? '')}
        onChange={e =>
          updateSet(exIdx, setIdx, isTimeBased ? 'time' : 'reps', e.target.value)
        }
      />

      {/* Complete checkmark */}
      <button
        style={{
          ...styles.checkBtn,
          background: set.completed ? '#2563EB' : 'transparent',
          border: `2px solid ${set.completed ? '#2563EB' : '#4B5563'}`,
        }}
        onClick={() => completeSet(exIdx, setIdx, settings)}
        aria-label={set.completed ? 'Mark incomplete' : 'Complete set'}
      >
        {set.completed && <Check size={13} color="#fff" strokeWidth={3} />}
      </button>
    </div>
  );
}

// ── Exercise 3-dot menu ───────────────────────────────────────────────────────
function ExerciseMenu({ exIdx, totalExercises, onClose, onAddNote, onSetRest, onToggleSuperset, onMoveUp, onMoveDown, onRemove }) {
  const ref = useRef(null);

  useEffect(() => {
    function handle(e) {
      if (ref.current && !ref.current.contains(e.target)) onClose();
    }
    document.addEventListener('mousedown', handle);
    document.addEventListener('touchstart', handle);
    return () => {
      document.removeEventListener('mousedown', handle);
      document.removeEventListener('touchstart', handle);
    };
  }, [onClose]);

  return (
    <div ref={ref} style={styles.exMenuDrop}>
      <button style={styles.exMenuItem} onClick={onAddNote}>
        <FileText size={14} />
        Add Note
      </button>
      <button style={styles.exMenuItem} onClick={onSetRest}>
        <Clock size={14} />
        Set Rest Timer
      </button>
      {exIdx < totalExercises - 1 && (
        <button style={styles.exMenuItem} onClick={onToggleSuperset}>
          <Link size={14} />
          Toggle Superset with Next
        </button>
      )}
      <div style={styles.menuDivider} />
      <button
        style={{ ...styles.exMenuItem, opacity: exIdx === 0 ? 0.35 : 1 }}
        disabled={exIdx === 0}
        onClick={onMoveUp}
      >
        <ArrowUp size={14} />
        Move Up
      </button>
      <button
        style={{ ...styles.exMenuItem, opacity: exIdx === totalExercises - 1 ? 0.35 : 1 }}
        disabled={exIdx === totalExercises - 1}
        onClick={onMoveDown}
      >
        <ArrowDown size={14} />
        Move Down
      </button>
      <div style={styles.menuDivider} />
      <button style={{ ...styles.exMenuItem, color: '#F87171' }} onClick={onRemove}>
        <Trash2 size={14} color="#F87171" />
        Remove Exercise
      </button>
    </div>
  );
}

// ── Note Modal ────────────────────────────────────────────────────────────────
function NoteModal({ exIdx, currentNote, onSave, onClose }) {
  const [note, setNote] = useState(currentNote ?? '');

  return (
    <div style={styles.modalBackdrop} onClick={onClose}>
      <div style={styles.modalBox} onClick={e => e.stopPropagation()}>
        <div style={styles.modalTitle}>Exercise Note</div>
        <textarea
          style={styles.noteTextarea}
          placeholder="Add a note for this exercise…"
          value={note}
          onChange={e => setNote(e.target.value)}
          autoFocus
          rows={4}
        />
        <div style={styles.modalActions}>
          <button style={styles.modalCancelBtn} onClick={onClose}>
            Cancel
          </button>
          <button
            style={styles.modalSaveBtn}
            onClick={() => {
              onSave(note);
              onClose();
            }}
          >
            Save
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Rest Time Modal ───────────────────────────────────────────────────────────
function RestTimeModal({ exIdx, currentRest, defaultRest, onSave, onClose }) {
  const [secs, setSecs] = useState(currentRest ?? defaultRest ?? 90);

  return (
    <div style={styles.modalBackdrop} onClick={onClose}>
      <div style={styles.modalBox} onClick={e => e.stopPropagation()}>
        <div style={styles.modalTitle}>Rest Timer</div>
        <div style={{ color: '#9CA3AF', fontSize: 13, marginBottom: 14 }}>
          Override rest time for this exercise.
        </div>
        <div style={styles.restModalRow}>
          <button
            style={styles.restModalAdj}
            onClick={() => setSecs(s => Math.max(0, s - 15))}
          >
            −15
          </button>
          <div style={styles.restModalDisplay}>
            <span style={{ fontSize: 28, fontWeight: 700, color: '#F9FAFB' }}>{secs}</span>
            <span style={{ fontSize: 13, color: '#9CA3AF', marginLeft: 4 }}>sec</span>
          </div>
          <button
            style={styles.restModalAdj}
            onClick={() => setSecs(s => Math.min(600, s + 15))}
          >
            +15
          </button>
        </div>
        <input
          type="range"
          min={0}
          max={600}
          step={5}
          value={secs}
          onChange={e => setSecs(Number(e.target.value))}
          style={{ width: '100%', marginBottom: 20, accentColor: '#3B82F6' }}
        />
        <div style={styles.modalActions}>
          <button style={styles.modalCancelBtn} onClick={onClose}>
            Cancel
          </button>
          <button
            style={styles.modalSaveBtn}
            onClick={() => {
              onSave(secs);
              onClose();
            }}
          >
            Set Timer
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Exercise Card ─────────────────────────────────────────────────────────────
function ExerciseCard({ ex, exIdx, totalExercises, showMenu, onMenuOpen, onMenuClose }) {
  const {
    toggleCollapse,
    addSet,
    removeExercise,
    updateNote,
    updateRestTime,
    toggleSuperset,
  } = useWorkout();

  const [editingNote, setEditingNote] = useState(false);
  const [editingRest, setEditingRest] = useState(false);
  const { settings } = useApp();

  const isTimeBased = ex.trackingType === 'time';
  const completedSets = ex.sets?.filter(s => s.completed).length ?? 0;

  return (
    <>
      <div style={styles.exCard}>
        {/* Card header */}
        <div style={styles.exCardHeader}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={styles.exCardName}>{ex.name}</div>
            {ex.note ? (
              <div style={styles.exNote}>{ex.note}</div>
            ) : null}
          </div>

          <div style={styles.exCardActions}>
            <span style={styles.exSetBadge}>
              {completedSets}/{ex.sets?.length ?? 0}
            </span>
            <button
              style={styles.iconBtn}
              onClick={() => toggleCollapse(exIdx)}
              aria-label={ex.collapsed ? 'Expand' : 'Collapse'}
            >
              {ex.collapsed
                ? <ChevronDown size={16} color="#9CA3AF" />
                : <ChevronUp size={16} color="#9CA3AF" />}
            </button>
            <div style={{ position: 'relative' }}>
              <button
                style={styles.iconBtn}
                onClick={() => showMenu ? onMenuClose() : onMenuOpen(exIdx)}
                aria-label="Exercise options"
              >
                <MoreVertical size={16} color="#9CA3AF" />
              </button>
              {showMenu && (
                <ExerciseMenu
                  exIdx={exIdx}
                  totalExercises={totalExercises}
                  onClose={onMenuClose}
                  onAddNote={() => { onMenuClose(); setEditingNote(true); }}
                  onSetRest={() => { onMenuClose(); setEditingRest(true); }}
                  onToggleSuperset={() => { onMenuClose(); toggleSuperset(exIdx); }}
                  onMoveUp={() => { onMenuClose(); }}
                  onMoveDown={() => { onMenuClose(); }}
                  onRemove={() => { onMenuClose(); removeExercise(exIdx); }}
                />
              )}
            </div>
          </div>
        </div>

        {/* Collapsed state */}
        {ex.collapsed ? (
          <div style={styles.collapsedRow}>
            {completedSets} set{completedSets !== 1 ? 's' : ''} completed
          </div>
        ) : (
          <>
            {/* Column headers */}
            <div style={styles.setHeaders}>
              <span style={{ width: 28, textAlign: 'center' }}>TYPE</span>
              <span style={{ width: 28, textAlign: 'center' }}>SET</span>
              <span style={{ flex: 1, textAlign: 'center' }}>PREVIOUS</span>
              <span style={{ width: 64, textAlign: 'center' }}>
                {settings.units === 'lbs' ? 'LBS' : 'KG'}
              </span>
              <span style={{ width: 64, textAlign: 'center' }}>
                {isTimeBased ? 'SEC' : 'REPS'}
              </span>
              <span style={{ width: 40 }} />
            </div>

            {/* Set rows */}
            {(ex.sets ?? []).map((set, si) => (
              <SetRow
                key={si}
                set={set}
                setIdx={si}
                exIdx={exIdx}
                isTimeBased={isTimeBased}
              />
            ))}

            {/* Add Set */}
            <button
              style={styles.addSetBtn}
              onClick={() => addSet(exIdx)}
            >
              + Add Set
            </button>
          </>
        )}
      </div>

      {/* Note modal */}
      {editingNote && (
        <NoteModal
          exIdx={exIdx}
          currentNote={ex.note}
          onSave={note => updateNote(exIdx, note)}
          onClose={() => setEditingNote(false)}
        />
      )}

      {/* Rest time modal */}
      {editingRest && (
        <RestTimeModal
          exIdx={exIdx}
          currentRest={ex.restTime}
          defaultRest={settings.defaultRest}
          onSave={secs => updateRestTime(exIdx, secs)}
          onClose={() => setEditingRest(false)}
        />
      )}
    </>
  );
}

// ── Superset Wrapper ──────────────────────────────────────────────────────────
function SupersetWrap({ children }) {
  return (
    <div style={styles.supersetWrap}>
      <div style={styles.supersetLabel}>SUPERSET</div>
      {children}
    </div>
  );
}

// ── Workout Complete Screen ───────────────────────────────────────────────────
function WorkoutComplete({ session, elapsed, onSave, onBack }) {
  const { setTitle, prs } = useWorkout();
  const { settings } = useApp();
  const [saving, setSaving] = useState(false);

  const volume = calcVolume(session?.exercises ?? []);
  const totalSets = calcSets(session?.exercises ?? []);
  const duration = elapsed;

  async function handleSave() {
    setSaving(true);
    try {
      await onSave();
    } finally {
      setSaving(false);
    }
  }

  return (
    <div style={styles.wcScreen}>
      <div style={styles.wcInner}>
        <div style={styles.wcTrophy}>🏆</div>
        <div style={styles.wcTitle}>Workout Complete!</div>

        {/* Editable title */}
        <input
          style={styles.wcTitleInput}
          value={session?.title ?? ''}
          onChange={e => setTitle(e.target.value)}
          placeholder="Workout Title"
        />

        {/* Stats grid */}
        <div style={styles.wcStatsGrid}>
          <div style={styles.wcStatCell}>
            <div style={styles.wcStatVal}>{fmtDuration(duration)}</div>
            <div style={styles.wcStatLabel}>Duration</div>
          </div>
          <div style={styles.wcStatCell}>
            <div style={styles.wcStatVal}>{fmtVolume(volume, settings.units)}</div>
            <div style={styles.wcStatLabel}>Volume</div>
          </div>
          <div style={styles.wcStatCell}>
            <div style={styles.wcStatVal}>{totalSets}</div>
            <div style={styles.wcStatLabel}>Sets</div>
          </div>
        </div>

        {/* PRs */}
        {prs.length > 0 && (
          <div style={styles.wcSection}>
            <div style={styles.wcSectionTitle}>Personal Records</div>
            {prs.map((pr, i) => (
              <div key={i} style={styles.wcPrRow}>
                <span style={styles.wcPrBadge}>PR</span>
                <span style={styles.wcPrName}>{pr.exerciseName}</span>
                <span style={styles.wcPrVal}>
                  {pr.weight} {settings.units} × {pr.reps}
                </span>
              </div>
            ))}
          </div>
        )}

        {/* Exercise summary */}
        <div style={styles.wcSection}>
          <div style={styles.wcSectionTitle}>Exercises</div>
          {(session?.exercises ?? []).map((ex, i) => {
            const done = ex.sets?.filter(s => s.completed).length ?? 0;
            const total = ex.sets?.length ?? 0;
            return (
              <div key={i} style={styles.wcExRow}>
                <span style={styles.wcExName}>{ex.name}</span>
                <span style={styles.wcExSets}>
                  {done}/{total} sets
                </span>
              </div>
            );
          })}
        </div>

        {/* Save button */}
        <button
          style={{ ...styles.saveWorkoutBtn, opacity: saving ? 0.6 : 1 }}
          disabled={saving}
          onClick={handleSave}
        >
          {saving ? 'Saving…' : 'Save Workout'}
        </button>

        <button style={styles.wcBackBtn} onClick={onBack}>
          Back to Workout
        </button>
      </div>
    </div>
  );
}

// ── LiveWorkout (main export) ─────────────────────────────────────────────────

export default function LiveWorkout({ onFinished }) {
  const {
    session,
    elapsed,
    restTimer,
    prBanner,
    cancelSession,
    finishSession,
    setTitle,
    addExercise,
    skipRestTimer,
    adjustRestTimer,
  } = useWorkout();
  const { settings } = useApp();

  const [showMenu, setShowMenu] = useState(null); // null | exIdx
  const [showComplete, setShowComplete] = useState(false);
  const [showPicker, setShowPicker] = useState(false);
  const bodyRef = useRef(null);

  if (!session) return null;

  const exercises = session.exercises ?? [];

  // Compute progress
  const totalSets = exercises.reduce((a, ex) => a + (ex.sets?.length ?? 0), 0);
  const completedSets = exercises.reduce(
    (a, ex) => a + (ex.sets?.filter(s => s.completed).length ?? 0),
    0
  );
  const progressPct = totalSets > 0 ? (completedSets / totalSets) * 100 : 0;

  // Build groups: consecutive exercises with same supersetGroupId are grouped
  function buildGroups(exs) {
    const groups = [];
    let i = 0;
    while (i < exs.length) {
      const ex = exs[i];
      const gid = ex.supersetGroupId;
      if (gid && i + 1 < exs.length && exs[i + 1].supersetGroupId === gid) {
        // Start a superset group
        const members = [{ ex, idx: i }];
        let j = i + 1;
        while (j < exs.length && exs[j].supersetGroupId === gid) {
          members.push({ ex: exs[j], idx: j });
          j++;
        }
        groups.push({ type: 'superset', members });
        i = j;
      } else {
        groups.push({ type: 'single', ex, idx: i });
        i++;
      }
    }
    return groups;
  }

  const groups = buildGroups(exercises);

  async function handlePick(ex) {
    setShowPicker(false);
    await addExercise(ex, settings);
    // scroll to bottom
    setTimeout(() => {
      bodyRef.current?.scrollTo({ top: bodyRef.current.scrollHeight, behavior: 'smooth' });
    }, 100);
  }

  async function handleFinishConfirm() {
    try {
      await finishSession();
      onFinished?.();
    } catch (err) {
      console.error('Save failed:', err);
      alert('Could not save workout. Please try again.');
    }
  }

  // If showing workout complete overlay
  if (showComplete) {
    return (
      <div style={styles.overlay}>
        <WorkoutComplete
          session={session}
          elapsed={elapsed}
          onSave={handleFinishConfirm}
          onBack={() => setShowComplete(false)}
        />
      </div>
    );
  }

  return (
    <div style={styles.overlay}>
      {/* PR Banner */}
      <PrBanner prBanner={prBanner} />

      {/* Fixed header */}
      <div style={styles.liveHeader}>
        <div style={styles.liveTimer}>{fmtTime(elapsed)}</div>
        <input
          style={styles.liveTitleInput}
          value={session.title}
          onChange={e => setTitle(e.target.value)}
          placeholder="Workout Title"
        />
        <button
          style={styles.finishBtn}
          onClick={() => setShowComplete(true)}
        >
          Finish
        </button>
      </div>

      {/* Progress bar */}
      <div style={styles.progressTrack}>
        <div
          style={{
            ...styles.progressFill,
            width: `${progressPct}%`,
            transition: 'width 0.4s ease',
          }}
        />
      </div>

      {/* Scrollable body */}
      <div ref={bodyRef} style={styles.liveBody}>
        {/* Exercise groups */}
        {groups.map((group, gi) => {
          if (group.type === 'superset') {
            return (
              <SupersetWrap key={`ss-${gi}`}>
                {group.members.map(({ ex, idx }) => (
                  <ExerciseCard
                    key={idx}
                    ex={ex}
                    exIdx={idx}
                    totalExercises={exercises.length}
                    showMenu={showMenu === idx}
                    onMenuOpen={i => setShowMenu(i)}
                    onMenuClose={() => setShowMenu(null)}
                  />
                ))}
              </SupersetWrap>
            );
          }
          return (
            <ExerciseCard
              key={group.idx}
              ex={group.ex}
              exIdx={group.idx}
              totalExercises={exercises.length}
              showMenu={showMenu === group.idx}
              onMenuOpen={i => setShowMenu(i)}
              onMenuClose={() => setShowMenu(null)}
            />
          );
        })}

        {exercises.length === 0 && (
          <div style={styles.liveEmpty}>
            <div style={{ fontSize: 14, color: '#6B7280', textAlign: 'center', padding: '40px 0' }}>
              No exercises yet. Tap "+ Add Exercise" below.
            </div>
          </div>
        )}

        {/* Add Exercise button */}
        <button
          style={styles.addExBtn}
          onClick={() => setShowPicker(true)}
        >
          <Plus size={16} style={{ marginRight: 8 }} />
          Add Exercise
        </button>

        {/* Cancel workout */}
        <button
          style={styles.cancelWorkoutBtn}
          onClick={() => {
            if (window.confirm('Cancel this workout? All progress will be lost.')) {
              cancelSession();
            }
          }}
        >
          Cancel Workout
        </button>

        {/* Bottom spacer for rest timer */}
        <div style={{ height: restTimer ? 100 : 32 }} />
      </div>

      {/* Rest timer */}
      <RestTimerOverlay
        restTimer={restTimer}
        onSkip={skipRestTimer}
        onAdjust={adjustRestTimer}
      />

      {/* Exercise picker sheet */}
      {showPicker && (
        <div style={styles.sheetBackdrop} onClick={() => setShowPicker(false)}>
          <div style={styles.sheetPanel} onClick={e => e.stopPropagation()}>
            <div style={styles.sheetHandle} />
            <div style={styles.sheetHeaderRow}>
              <span style={styles.sheetTitleText}>Add Exercise</span>
              <button
                style={styles.iconBtn}
                onClick={() => setShowPicker(false)}
                aria-label="Close"
              >
                <X size={20} color="#9CA3AF" />
              </button>
            </div>
            <div style={styles.sheetBody}>
              <ExercisesTab pickerMode onPick={handlePick} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

